// A class bundles data (properties) and behavior (methods)
class Animal {
  name: string;           // property declaration
  constructor(name: string) {
    this.name = name;     // assign the parameter to the property
  }
}

// public in the constructor auto-creates the property AND assigns it
class Animal {
  constructor(public name: string) {} // no separate declaration needed
}

const dog = new Animal('Dog');
console.log(dog.name); // 'Dog'

// Methods are functions defined inside the class body
class Rectangle {
  constructor(public width: number, public height: number) {}

  area(): number {
    return this.width * this.height;
  }

  perimeter(): number {
    return 2 * (this.width + this.height);
  }
}

// public — accessible everywhere (this is the default)
// private — only accessible inside THIS class
// protected — accessible in this class and subclasses
class BankAccount {
  public owner: string;
  private balance: number;            // hidden from outside code
  protected accountNumber: string;     // visible to child classes

  constructor(owner: string, initial: number) {
    this.owner = owner;
    this.balance = initial;
    this.accountNumber = 'ACC-' + Math.random();
  }
}

// Getters compute values dynamically, setters validate on assignment
class Temperature {
  constructor(private celsius: number) {}

  get fahrenheit(): number {
    return this.celsius * 9 / 5 + 32; // computed on access
  }

  set fahrenheit(value: number) {
    this.celsius = (value - 32) * 5 / 9; // converts on assignment
  }
}

// extends creates a child class inheriting from the parent
class Vehicle {
  constructor(public speed: number) {}
  move(): void {
    console.log('Moving at ' + this.speed);
  }
}

class Car extends Vehicle {
  honk(): void {
    console.log('Beep beep!'); // Car-specific behavior
  }
}

// Child classes can override parent methods with their own version
class Animal {
  speak(): void {
    console.log('Animal makes a sound');
  }
}

class Dog extends Animal {
  speak(): void {
    console.log('Woof!'); // replaces the parent speak()
  }
}
